  return (
    <div>
      <Navbar className="" fluid rounded >
        <Link to="/">
          <span className="self-center whitespace-nowrap text-xl font-semibold dark:text-white">
            Movie Channel
          </span>
        </Link>
        <div className="flex md:order-2">
          <form action="" className="text-black flex items-center justify-center">
           <TextInput  placeholder="Search..." value={movieName} onChange={(e)=>setMovieName(e.target.value)}/>
               <Button className="ms-2" onClick={()=>searchMovie()} color="dark" type="button">Click</Button>
          </form>

         
        </div>
      </Navbar>
    </div>
  );
}};

export default Header;
